#!/usr/bin/env python3
"""
Plugin pose_posture
Analiza la postura principal (standing, sitting, kneeling, lying, on_all_fours)
basándose en las coordenadas de los puntos clave del esqueleto. 
"""

from plugins.common.plugin_entry import nv_enrich_plugin


@nv_enrich_plugin("pose_posture", result_scope="detection")
def process_job(job):
    """
    Analiza la postura dominante de una persona a partir de sus keypoints.
    Estructura esperada: job = {"detection": {...}, "frame": {...}}
    donde detection es el registro de pose (class_name="person", keypoints=[...]).
    """
    pose = job.get("detection")
    if not pose or pose.get("class_name") != "person":
        return {"posture": "unknown", "reason": "no_person_or_invalid_input"}

    keypoints = pose.get("keypoints", [])
    if not keypoints:
        return {"posture": "unknown", "reason": "no_keypoints"}

    # Indexar keypoints por nombre (filtrando poca confianza)
    kp = {k["name"]: k for k in keypoints if k.get("confidence", 0) > 0.5}

    def y(name): return kp[name]["y"] if name in kp else None
    def x(name): return kp[name]["x"] if name in kp else None  # (x no usado aun, queda por si hace falta)

    required = [
        "left_hip", "right_hip", "left_knee", "right_knee",
        "left_ankle", "right_ankle", "left_shoulder", "right_shoulder"
    ]
    if not all(k in kp for k in required):
        return {"posture": "unknown", "reason": "missing_keypoints"}

    # Promedios verticales (y va 0=>arriba, 1=>abajo)
    hip_y = (y("left_hip") + y("right_hip")) / 2
    knee_y = (y("left_knee") + y("right_knee")) / 2
    ankle_y = (y("left_ankle") + y("right_ankle")) / 2
    shoulder_y = (y("left_shoulder") + y("right_shoulder")) / 2

    torso_len = abs(shoulder_y - hip_y)
    thigh_len = abs(hip_y - knee_y)
    calf_len = abs(knee_y - ankle_y)
    total_height = max(abs(shoulder_y - ankle_y), 1e-6)  # evita división por 0

    ratios = {
        "hip_knee_ratio": round(thigh_len / total_height, 3),
        "knee_ankle_ratio": round(calf_len / total_height, 3),
        "torso_ratio": round(torso_len / total_height, 3)
    }

    posture = "unknown"
    explanation = ""

    is_vertical = shoulder_y < hip_y < knee_y < ankle_y
    is_flat = abs(shoulder_y - ankle_y) < 0.1
    hip_near_knee = abs(hip_y - knee_y) < 0.1
    hip_near_ankle = abs(hip_y - ankle_y) < 0.1

    if is_vertical and torso_len / total_height > 0.35:
        posture = "standing"
        explanation = "alignment vertical"
    elif hip_near_knee and not is_flat:
        posture = "sitting"
        explanation = "hip near knees, torso vertical"
    elif hip_near_ankle and not is_flat:
        posture = "kneeling"
        explanation = "hips close to ankles"
    elif is_flat:
        posture = "lying"
        explanation = "body aligned horizontally"
    else:
        lw_y = kp.get("left_wrist", {}).get("y")
        rw_y = kp.get("right_wrist", {}).get("y")
        if lw_y is not None and rw_y is not None and (
            abs(lw_y - knee_y) < 0.1 or abs(rw_y - knee_y) < 0.1
        ):
            posture = "on_all_fours"
            explanation = "wrists and knees near same height"
        else:
            posture = "unknown"
            explanation = "no clear pattern"

    return {
        "posture": posture,
        "explanation": explanation,
        **ratios
    }
